#include <bits/stdc++.h>
using namespace std;

const int N=140010,V=1e6+10;

struct Node{
    int x,u,v;
}ch[N];

struct Qu{
    int l,r,t,id;
}qu[N];

int n,m,a[N],b[N],tot1,tot2,len,ans[N],sum[V],cnt;

int calc(int x){
    return (x-1)/len+1;
}

bool cmp(Qu x,Qu y){
    if(calc(x.t)==calc(y.t)){
        if(calc(x.l)==calc(y.l))
            return x.r<y.r;
        return calc(x.l)<calc(y.l);
    }
    return calc(x.t)<calc(y.t);
}

void add(int x,int k){
    sum[x]+=k;
    if(k==-1 && sum[x]==0) cnt--;
    if(k==1 && sum[x]==1) cnt++;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        b[i]=a[i];
    }
    for(int i=1;i<=m;i++){
        char op[2];
        int x,y;
        scanf("%s",op);
        scanf("%d%d",&x,&y);
        if(op[0]=='Q'){
            tot1++;
            qu[tot1]={x,y,tot2,tot1};
        }else{
            tot2++;
            ch[tot2]={x,b[x],y};
            b[x]=y;
        }
    }
    while(1ll*(len+1)*(len+1)*(len+1)<=n)
        len++;
    len*=len;
    sort(qu+1,qu+tot1+1,cmp);
    int l=1,r=0,t=0;
    for(int i=1;i<=tot1;i++){
        while(t<qu[i].t){
            t++;
            if(l<=ch[t].x && ch[t].x<=r)
                add(ch[t].u,-1),add(ch[t].v,1);
            a[ch[t].x]=ch[t].v;
        }
        while(t>qu[i].t){
            if(l<=ch[t].x && ch[t].x<=r)
                add(ch[t].v,-1),add(ch[t].u,1);
            a[ch[t].x]=ch[t].u;
            t--;
        }
        while(l<qu[i].l) add(a[l],-1),l++;
        while(l>qu[i].l) l--,add(a[l],1);
        while(r<qu[i].r) r++,add(a[r],1);
        while(r>qu[i].r) add(a[r],-1),r--;
        ans[qu[i].id]=cnt;
    }
    for(int i=1;i<=tot1;i++)
        printf("%d\n",ans[i]);
    return 0;
}
